blocks.en:
flowchart TD
  A[Receive EAPOL PDU] --> B{Dest addr OK?}
  B -- no --> X[Discard]
  B -- yes --> C{PAE Ethertype + >=2 octets?}
  C -- no --> X
  C -- yes --> D{Packet Type in Table 11-3?}
  D -- no --> X
  D -- yes --> E{Body Length fits frame?}
  E -- no --> X
  E -- yes --> F[Dispatch by Packet Type]

blocks.zh:
flowchart TD
  A[收到 EAPOL PDU] --> B{目的地址正确?}
  B -- 否 --> X[丢弃]
  B -- 是 --> C{有 PAE 以太网类型且>=2 八位组?}
  C -- 否 --> X
  C -- 是 --> D{报文类型在表 11-3 中?}
  D -- 否 --> X
  D -- 是 --> E{报文体长度合于帧内?}
  E -- 否 --> X
  E -- 是 --> F[按报文类型分发]
